<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand Sandbox</title>
<style>
  :root{
    --bg:#0d0d12; --panel:#17171f; --edge:#2a2a36; --text:#e6e6ef;
    --sand:#d9bb7a; --water:#3a7bd5; --wall:#8a8a95; --acid:#8dff3a; --empty:#101016;
  }
  *{box-sizing:border-box}
  html,body{height:100%}
  body{
    margin:0; background:radial-gradient(1200px 600px at 50% -10%,#181824,#0d0d12);
    color:var(--text); font-family:system-ui,Segoe UI,Roboto,Arial,sans-serif;
    display:flex; flex-direction:column; align-items:center; justify-content:center;
    min-height:100vh; gap:18px; padding:24px;
  }
  h1{margin:0; font-size:20px; font-weight:600; letter-spacing:.5px; color:#c9c9d8}
  h1 span{color:var(--acid)}
  #wrap{display:flex; flex-direction:column; align-items:center; gap:14px}
  #sand{
    background:var(--empty); border:1px solid var(--edge); border-radius:10px;
    box-shadow:0 12px 40px rgba(0,0,0,.55), inset 0 0 0 1px rgba(255,255,255,.02);
    cursor:crosshair; touch-action:none; image-rendering:pixelated;
  }
  #controls{
    display:flex; flex-wrap:wrap; gap:8px; justify-content:center;
    background:var(--panel); padding:10px; border:1px solid var(--edge); border-radius:12px;
  }
  button{
    appearance:none; border:1px solid var(--edge); color:var(--text);
    background:#20202b; padding:8px 14px; border-radius:9px; font-size:13px;
    cursor:pointer; transition:transform .05s ease, box-shadow .15s ease, background .15s ease;
    display:flex; align-items:center; gap:8px; font-weight:500;
  }
  button:hover{background:#2a2a38}
  button:active{transform:translateY(1px)}
  button.active{box-shadow:0 0 0 2px var(--dot,#fff) inset, 0 0 12px rgba(255,255,255,.08); background:#2c2c3c}
  .swatch{width:12px; height:12px; border-radius:3px; border:1px solid rgba(0,0,0,.4)}
  #mat-sand .swatch{background:var(--sand)}
  #mat-water .swatch{background:var(--water)}
  #mat-wall .swatch{background:var(--wall)}
  #mat-acid .swatch{background:var(--acid)}
  #mat-empty .swatch{background:var(--empty); border:1px solid var(--edge)}
  #clear{background:#3a1f24; border-color:#5a2b32}
  #clear:hover{background:#4a262c}
  .hint{font-size:12px; color:#7a7a8a}
</style>
</head>
<body>
  <h1>Falling&nbsp;<span>Sand</span>&nbsp;Sandbox</h1>
  <div id="wrap">
    <canvas id="sand" width="480" height="480"></canvas>
    <div id="controls">
      <button id="mat-sand"  style="--dot:var(--sand)"  class="active"><span class="swatch"></span>Sand</button>
      <button id="mat-water" style="--dot:var(--water)"><span class="swatch"></span>Water</button>
      <button id="mat-wall"  style="--dot:var(--wall)"><span class="swatch"></span>Wall</button>
      <button id="mat-acid"  style="--dot:var(--acid)"><span class="swatch"></span>Acid</button>
      <button id="mat-empty" style="--dot:#888"><span class="swatch"></span>Eraser</button>
      <button id="clear">✕ Clear</button>
    </div>
    <div class="hint">Click &amp; drag on the canvas to paint · particles fall in real time</div>
  </div>

<script>
(function(){
  "use strict";

  // ---- material codes ----
  const EMPTY=0, SAND=1, WATER=2, WALL=3, ACID=4;
  const NAME = ["empty","sand","water","wall","acid"];
  const CODE = {empty:EMPTY, sand:SAND, water:WATER, wall:WALL, acid:ACID};

  // ---- grid ----
  const W = 120, H = 120;          // >= 80x80
  const CELL = 4;                  // 120*4 = 480 CSS px (>= 400)
  const grid  = new Uint8Array(W*H);
  const moved = new Uint8Array(W*H);
  const idx = (x,y)=> y*W + x;

  function swap(i,j){
    const t = grid[i]; grid[i] = grid[j]; grid[j] = t;
    moved[i] = 1; moved[j] = 1;
  }

  // ---- per-particle rules ----
  function stepSand(x,y){
    const i = idx(x,y);
    if(y+1 < H){
      const bi = idx(x,y+1), b = grid[bi];
      if(b===EMPTY || b===WATER || b===ACID){ swap(i,bi); return; }   // fall / sink
      const d = Math.random()<0.5 ? -1 : 1;                            // slide diagonally
      for(const dx of [d,-d]){
        const nx = x+dx;
        if(nx>=0 && nx<W){
          const di = idx(nx,y+1), t = grid[di];
          if(t===EMPTY || t===WATER || t===ACID){ swap(i,di); return; }
        }
      }
    }
  }

  function stepWater(x,y){
    const i = idx(x,y);
    if(y+1 < H){
      const bi = idx(x,y+1);
      if(grid[bi]===EMPTY){ swap(i,bi); return; }                      // fall
      const d = Math.random()<0.5 ? -1 : 1;
      for(const dx of [d,-d]){                                          // diagonal down
        const nx = x+dx;
        if(nx>=0 && nx<W){ const di = idx(nx,y+1); if(grid[di]===EMPTY){ swap(i,di); return; } }
      }
    }
    const d = Math.random()<0.5 ? -1 : 1;                              // spread sideways (escape around)
    for(const dx of [d,-d]){
      const nx = x+dx;
      if(nx>=0 && nx<W){ const ni = idx(nx,y); if(grid[ni]===EMPTY){ swap(i,ni); return; } }
    }
  }

  function stepAcid(x,y){
    const i = idx(x,y);
    // dissolve sand/wall below or beside — acid is consumed, target eroded
    const targets = [[x,y+1],[x-1,y],[x+1,y]];
    for(const t of targets){
      const nx=t[0], ny=t[1];
      if(nx>=0 && nx<W && ny>=0 && ny<H){
        const ni = idx(nx,ny), c = grid[ni];
        if(c===SAND || c===WALL){
          grid[ni] = EMPTY; grid[i] = EMPTY;
          moved[ni] = 1; moved[i] = 1;
          return;
        }
      }
    }
    // otherwise flow like water
    if(y+1 < H){
      const bi = idx(x,y+1);
      if(grid[bi]===EMPTY){ swap(i,bi); return; }
      const d = Math.random()<0.5 ? -1 : 1;
      for(const dx of [d,-d]){
        const nx = x+dx;
        if(nx>=0 && nx<W){ const di = idx(nx,y+1); if(grid[di]===EMPTY){ swap(i,di); return; } }
      }
    }
    const d = Math.random()<0.5 ? -1 : 1;
    for(const dx of [d,-d]){
      const nx = x+dx;
      if(nx>=0 && nx<W){ const ni = idx(nx,y); if(grid[ni]===EMPTY){ swap(i,ni); return; } }
    }
  }

  // ---- one simulation step: bottom row up, one move per cell ----
  function stepOnce(){
    moved.fill(0);
    for(let y=H-1; y>=0; y--){
      for(let x=0; x<W; x++){
        const i = idx(x,y);
        if(moved[i]) continue;
        const c = grid[i];
        if(c===SAND)       stepSand(x,y);
        else if(c===WATER) stepWater(x,y);
        else if(c===ACID)  stepAcid(x,y);
      }
    }
  }

  // ---- rendering ----
  const canvas = document.getElementById("sand");
  const ctx = canvas.getContext("2d");
  const colors = {
    [SAND]:"#d9bb7a", [WATER]:"#3a7bd5", [WALL]:"#8a8a95", [ACID]:"#8dff3a"
  };
  function draw(){
    ctx.fillStyle = "#101016";
    ctx.fillRect(0,0,canvas.width,canvas.height);
    for(let y=0; y<H; y++){
      for(let x=0; x<W; x++){
        const c = grid[idx(x,y)];
        if(c===EMPTY) continue;
        ctx.fillStyle = colors[c];
        ctx.fillRect(x*CELL, y*CELL, CELL, CELL);
      }
    }
  }

  // ---- continuous animation ----
  function loop(){ stepOnce(); draw(); requestAnimationFrame(loop); }
  requestAnimationFrame(loop);

  // ---- painting ----
  let current = SAND;
  let painting = false;
  const BRUSH = 2; // radius

  function paintAt(clientX, clientY){
    const r = canvas.getBoundingClientRect();
    const gx = Math.floor((clientX - r.left) / r.width  * W);
    const gy = Math.floor((clientY - r.top)  / r.height * H);
    for(let dy=-BRUSH; dy<=BRUSH; dy++){
      for(let dx=-BRUSH; dx<=BRUSH; dx++){
        if(dx*dx+dy*dy > BRUSH*BRUSH+1) continue;
        const x=gx+dx, y=gy+dy;
        if(x>=0 && x<W && y>=0 && y<H) grid[idx(x,y)] = current;
      }
    }
  }

  canvas.addEventListener("mousedown", e=>{ painting=true; paintAt(e.clientX,e.clientY); });
  window.addEventListener("mouseup", ()=> painting=false);
  window.addEventListener("mousemove", e=>{ if(painting) paintAt(e.clientX,e.clientY); });
  canvas.addEventListener("mouseleave", ()=>{}); // keep painting while button held
  // touch support
  canvas.addEventListener("touchstart", e=>{ painting=true; const t=e.touches[0]; paintAt(t.clientX,t.clientY); e.preventDefault(); }, {passive:false});
  canvas.addEventListener("touchmove",  e=>{ if(painting){ const t=e.touches[0]; paintAt(t.clientX,t.clientY); e.preventDefault(); } }, {passive:false});
  window.addEventListener("touchend", ()=> painting=false);

  // ---- material buttons ----
  const matButtons = {
    [SAND]:  document.getElementById("mat-sand"),
    [WATER]: document.getElementById("mat-water"),
    [WALL]:  document.getElementById("mat-wall"),
    [ACID]:  document.getElementById("mat-acid"),
    [EMPTY]: document.getElementById("mat-empty"),
  };
  function selectMat(code){
    current = code;
    for(const k in matButtons) matButtons[k].classList.toggle("active", +k===code);
  }
  matButtons[SAND ].addEventListener("click", ()=>selectMat(SAND));
  matButtons[WATER].addEventListener("click", ()=>selectMat(WATER));
  matButtons[WALL ].addEventListener("click", ()=>selectMat(WALL));
  matButtons[ACID ].addEventListener("click", ()=>selectMat(ACID));
  matButtons[EMPTY].addEventListener("click", ()=>selectMat(EMPTY));

  function clearGrid(){ grid.fill(EMPTY); }
  document.getElementById("clear").addEventListener("click", clearGrid);

  // ---- programmatic API ----
  window.sim = {
    w: W, h: H,
    tick(n){ n = n|0; for(let k=0;k<n;k++) stepOnce(); draw(); },
    get(x,y){
      if(x<0||x>=W||y<0||y>=H) return "wall"; // out of bounds = solid boundary
      return NAME[grid[idx(x,y)]];
    },
    set(x,y,material){
      if(x<0||x>=W||y<0||y>=H) return;
      const c = CODE[material];
      if(c===undefined) return;
      grid[idx(x,y)] = c;
    },
    clear(){ clearGrid(); }
  };
})();
</script>
</body>
</html>
